        count: Optional[Union[bool, 'types.VacationRequestCountAggregateInput']] = None,
        order: Optional[Union[Mapping['types.VacationRequestScalarFieldKeys', 'types.SortOrder'], List[Mapping['types.VacationRequestScalarFieldKeys', 'types.SortOrder']]]] = None,
